// Get the places array from the input data
const places = items[0]?.json?.body?.places || [];

// Create an output array to hold each place as a separate item
let output = [];

if (places.length > 0) {
  for (let i = 0; i < places.length; i++) {
    // For each place, push a new item into the output array
    output.push({
      json: {
        place: places[i], // The individual place object

        // ✅ ADDED: websiteUri (safe access)
        websiteUri: places[i]?.websiteUri || null,

        otherData: items[0].json.otherData || null // unchanged
      }
    });
  }
} else {
  // Log an error or handle the case where places array is empty or undefined
  console.log('Places array is empty or undefined.');
}

// Return the output array, so each place becomes its own item
return output;

const html = $json.data ?? '';

const cleanedText = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .toLowerCase();

const emailRegex = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi;

const matches = cleanedText.match(emailRegex) || [];

const blacklist = ['example.com', 'test.com', 'email.com', 'yourdomain.com'];

const emails = [...new Set(matches)].filter(e => !blacklist.some(b => e.includes(b)));

const placeData = $('Split Places Array').item.json.place;

return {
  place: placeData,
  email: emails.length ? emails[0] : null
};

