const today = new Date();

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d.toISOString().split("T")[0];
}

item.json.intro_date = addDays(today, 0);
item.json.fu1_date = addDays(today, 7);
item.json.fu2_date = addDays(today, 11);

item.json.intro_sent = "yes";
item.json.fu1_sent = "no";
item.json.fu2_sent = "no";

return item;
